When the select field in a create view select contains a comparision
How to repeat:
create table fig (id int not null primary key, varchar_1 varchar(20)) DEFAULT CHARACTER SET=utf8mb4 COLLATE=utf8mb4_bin;
create view v_substr as select substr(varchar_1,if((-(4) = 0),1,-(4)),4) AS `SUBSTR(varchar_1,-4,4)` from fig;
show create view v_substr;
